1102	func (s *service) startQuotaRecoveryProbeLoop() {
1103		if s == nil || s.providerQuota == nil {
1104			return
1105		}
1106		ctx := s.opts.QuotaRefreshContext
1107		if ctx == nil {
1108			ctx = context.Background()
1109		}
1110		probe := s.quotaRecoveryProber()
1111		if probe == nil {
1112			return
1113		}
1114		go runQuotaRecoveryProbeLoop(ctx, s.providerQuota, probe, defaultQuotaRecoveryFallbackInterval, nil, nil)
