1117	// quotaRecoveryProber returns the QuotaRecoveryProber used by the recovery
1118	// loop. It looks up the provider entry in ServiceConfig and reuses the same
1119	// probeProviderStatus the HealthCheck endpoint uses; a "connected" status
1120	// counts as recovery, anything else is reported as a probe failure so the
1121	// retry_after gets extended with backoff.
1122	func (s *service) quotaRecoveryProber() QuotaRecoveryProber {
1123		sc := s.opts.ServiceConfig
1124		if sc == nil {
1125			return nil
1126		}
1127		return func(ctx context.Context, name string) error {
1128			entry, ok := sc.Provider(name)
1129			if !ok {
1130				return fmt.Errorf("provider %q not found", name)
1131			}
1132			probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
1133			defer cancel()
1134			probe := probeProviderStatus(probeCtx, entry, time.Now().UTC())
1135			if probe.status == "connected" {
1136				return nil
1137			}
1138			if probe.detail != "" {
1139				return fmt.Errorf("%s", probe.detail)
1140			}
1141			return fmt.Errorf("%s", probe.status)
1142		}
1143	}
