1252	func serviceRoutingModelEligibility(entries []routing.HarnessEntry, cat *modelcatalog.Catalog) func(model string) (routing.ModelEligibility, bool) {
1253		if cat == nil {
1254			return nil
1255		}
1256		eligibility := make(map[string]routing.ModelEligibility)
1257		add := func(modelID string, includeByDefault bool, status string) {
1258			modelID = strings.TrimSpace(modelID)
1259			if modelID == "" {
1260				return
1261			}
1262			view := modeleligibility.Resolve(modelID, includeByDefault, status, cat)
1263			known := routing.ModelEligibility{
1264				Power:        view.Power,
1265				ExactPinOnly: view.ExactPinOnly,
1266				AutoRoutable: view.AutoRoutable,
1267			}
1268			if existing, ok := eligibility[modelID]; ok {
1269				if known.Power > existing.Power {
1270					existing.Power = known.Power
1271				}
1272				existing.ExactPinOnly = existing.ExactPinOnly || known.ExactPinOnly
1273				existing.AutoRoutable = existing.AutoRoutable || known.AutoRoutable
1274				eligibility[modelID] = existing
1275				return
1276			}
1277			eligibility[modelID] = known
1278		}
1279		for _, h := range entries {
1280			status := "available"
1281			if !h.Available {
1282				status = "unreachable"
1283			}
1284			if h.DefaultModel != "" {
1285				add(h.DefaultModel, true, status)
1286			}
1287			for _, modelID := range h.SupportedModels {
1288				add(modelID, true, status)
1289			}
1290			for _, p := range h.Providers {
1291				includeByDefault := !p.ExcludeFromDefaultRouting
1292				add(p.DefaultModel, includeByDefault, status)
1293				for _, modelID := range p.DiscoveredIDs {
1294					add(modelID, includeByDefault, status)
1295				}
1296			}
1297		}
1298		if len(eligibility) == 0 {
1299			return nil
1300		}
1301		return func(model string) (routing.ModelEligibility, bool) {
1302			known, ok := eligibility[strings.TrimSpace(model)]
1303			return known, ok
1304		}
1305	}
