48	func (s *service) listModelsForSubprocessHarness(filter ModelFilter) []ModelInfo {
49		name := harnesses.ResolveHarnessAlias(filter.Harness)
50		cfg, ok := s.registry.Get(name)
51		modelIDs := subprocessHarnessModelIDs(name, cfg)
52		if !ok || harnessRunsInProcessOrHTTP(cfg) || len(modelIDs) == 0 {
53			return nil
54		}
55		if filter.Provider != "" && filter.Provider != name {
56			return nil
57		}
58		cat, _ := modelcatalog.Default()
59		out := make([]ModelInfo, 0, len(modelIDs))
60		for i, id := range modelIDs {
61			info := ModelInfo{
62				ID:             id,
63				Provider:       name,
64				Harness:        name,
65				EndpointName:   name,
66				ServerInstance: name,
67				Capabilities:   []string{"streaming", "tool_use"},
68				Available:      true,
69				IsDefault:      cfg.DefaultModel != "" && id == cfg.DefaultModel,
70				Billing:        harnessPaymentKind(name, cfg),
71				RankPosition:   i,
72			}
73			if cat != nil {
74				info.ContextLength, info.ContextSource = resolveContextEvidence(context.Background(), ServiceProviderEntry{}, id, cat)
75				info.Cost, info.PerfSignal = catalogCostAndPerf(cat, id)
76				info.Power, info.AutoRoutable, info.ExactPinOnly = catalogPowerEligibility(cat, id)
77			}
78			info.Utilization = s.routeUtilizationEvidence(name, info.ServerInstance, info.EndpointName, id)
79			out = append(out, info)
80		}
81		return out
82	}
