104	func (s *service) listModelsFromSnapshot(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot, filter ModelFilter) []ModelInfo {
105		defaultProviderName := sc.DefaultProviderName()
106		entries := make(map[string]ServiceProviderEntry, len(sc.ProviderNames()))
107		for _, name := range sc.ProviderNames() {
108			if filter.Provider != "" && filter.Provider != name {
109				continue
110			}
111			entry, ok := sc.Provider(name)
112			if !ok {
113				continue
114			}
115			entries[name] = entry
116		}
117	
118		modelsByProvider := make(map[string][]modelsnapshot.KnownModel, len(snapshot.Models))
119		for _, model := range snapshot.Models {
120			if filter.Provider != "" && filter.Provider != model.Provider {
121				continue
122			}
123			if _, ok := entries[model.Provider]; !ok {
124				continue
125			}
126			modelsByProvider[model.Provider] = append(modelsByProvider[model.Provider], model)
127		}
128	
129		rankByEndpoint := make(map[string]int, len(snapshot.Models))
130		out := make([]ModelInfo, 0, len(snapshot.Models))
131		for _, providerName := range sc.ProviderNames() {
132			if filter.Provider != "" && filter.Provider != providerName {
133				continue
134			}
135			entry, ok := entries[providerName]
136			if !ok {
137				continue
138			}
139			for _, model := range modelsByProvider[providerName] {
140				normalizedModel := model
141				normalizedModel.ServerInstance = serverinstance.Normalize(model.EndpointBaseURL, model.ServerInstance)
142				rankKey := strings.Join([]string{normalizedModel.Provider, normalizedModel.EndpointName, normalizedModel.EndpointBaseURL, normalizedModel.ServerInstance}, "\x00")
143				rank := rankByEndpoint[rankKey]
144				rankByEndpoint[rankKey] = rank + 1
145				out = append(out, s.modelInfoFromSnapshotModel(ctx, providerName, entry, defaultProviderName, cat, normalizedModel, rank))
146			}
147		}
148		return out
149	}
