151	func (s *service) modelInfoFromSnapshotModel(ctx context.Context, providerName string, entry ServiceProviderEntry, defaultProviderName string, cat *modelcatalog.Catalog, model modelsnapshot.KnownModel, rankPosition int) ModelInfo {
152		info := ModelInfo{
153			ID:              model.ID,
154			Provider:        providerName,
155			ProviderType:    model.ProviderType,
156			Harness:         model.Harness,
157			EndpointName:    model.EndpointName,
158			EndpointBaseURL: model.EndpointBaseURL,
159			ServerInstance:  model.ServerInstance,
160			ContextLength:   model.ContextWindow,
161			Utilization:     s.routeUtilizationEvidence(providerName, model.ServerInstance, model.EndpointName, model.ID),
162			Capabilities:    providerCapabilities(entry),
163			Cost: CostInfo{
164				InputPerMTok:  model.CostInputPerM,
165				OutputPerMTok: model.CostOutputPerM,
166			},
167			Power:                         model.Power,
168			AutoRoutable:                  model.AutoRoutable,
169			ExactPinOnly:                  model.ExactPinOnly,
170			Billing:                       model.Billing,
171			ActualCashSpend:               model.ActualCashSpend,
172			EffectiveCost:                 model.EffectiveCost,
173			EffectiveCostSource:           model.EffectiveCostSource,
174			SupportsTools:                 model.SupportsTools,
175			DeploymentClass:               model.DeploymentClass,
176			HealthFreshnessAt:             model.HealthFreshnessAt,
177			HealthFreshnessSource:         model.HealthFreshnessSource,
178			QuotaFreshnessAt:              model.QuotaFreshnessAt,
179			QuotaFreshnessSource:          model.QuotaFreshnessSource,
180			ModelDiscoveryFreshnessAt:     model.DiscoveredAt,
181			ModelDiscoveryFreshnessSource: string(model.DiscoveredVia),
182			Available:                     true,
183			RankPosition:                  rankPosition,
184		}
185		if info.Harness == "" {
186			info.Harness = "fiz"
187		}
188		info.ContextLength, info.ContextSource = resolveContextEvidence(ctx, entry, model.ID, cat)
189		if cat != nil {
190			_, info.PerfSignal = catalogCostAndPerf(cat, model.ID)
191		}
192		info.IsDefault = providerName == defaultProviderName && entry.Model != "" && model.ID == entry.Model
193		return info
194	}
