176	func AppendUniqueModelIDs(values []string, additions ...string) []string {
177		for _, value := range additions {
178			value = strings.TrimSpace(value)
179			if value == "" {
180				continue
181			}
182			found := false
183			for _, existing := range values {
184				if existing == value {
185					found = true
186					break
187				}
188			}
189			if !found {
190				values = append(values, value)
191			}
192		}
193		return values
194	}
